        "executor": "provided",
        "calls": [
          {
            "outcomes": [
              {
                "return": true
              }
            ]
          },
          {
            "outcomes": [
              {
                "return": true
              }
            ]
          },
          {
            "outcomes": [
              {
                "return": true
              }
            ]
          }
        ]
      },
      "expected_output": "futures_done=3\ncompleted_successfully=3\nexecutor=provided\n"
