    {
      "input": {
        "policy": {
          "max_tries": 1,
          "backoff": "fixed",
          "delay_ms": 0,
          "retry_on": "fail_any_exception"
        },
        "executor": "provided",
        "calls": [
          {
            "outcomes": [
              {
                "throw": "runtime_error"
              }
            ]
          }
        ]
