    },
    {
      "input": {
        "policy": {
          "max_tries": 3,
          "backoff": "fixed",
          "delay_ms": 1,
          "custom_exception_rule": "message_contains_retry"
        },
        "operation": {
          "outcomes": [
            {
              "throw": "runtime_error",
              "message": "should NOT retry!"
            }
          ]
        }
      },
      "expected_output": "error=unexpected_exception\nexception=runtime_error\n"
    },
    {
      "input": {
        "policy": {
          "max_tries": 3,
          "backoff": "fixed",
          "delay_ms": 1,
