        },
        "operation": {
          "outcomes": [
            {
              "throw": "custom_error",
              "message": "test message",
              "value": -100
            }
          ]
        }
      },
      "expected_output": "error=unexpected_exception\nexception=custom_error\n"
    }
  ]
}

